// Pretty-print: mimic the reference's behavior.
// For block elements: leading newline, indented children, newline before close.
// For inline elements: no breaks of their own.
// For text-only block elements: text inline with open tag, newline before close.
fn pretty_print<W: Write + ?Sized>(out: &mut W, node: &NodeRef, depth: usize) -> io::Result<()> {
    match node.data() {
        NodeData::Element(el) => {
            let name = el.name.local.as_ref();
            let is_inline = is_inline_tag(name);
            let has_element_child = node.children().any(|c| matches!(c.data(), NodeData::Element(_)));
            // Write opening tag with attributes (alphabetized)
            if !is_inline && depth > 0 {
                // Block element nested: break before
            }
            write_start_tag(out, el)?;
            if !is_inline && has_element_child {
                // Recurse children with indent
                for child in node.children() {
                    pretty_print_child(out, &child, depth + 1)?;
                }
                // Closing tag with break/indent before
                out.write_all(b"\n")?;
                write_indent(out, depth)?;
                write_end_tag(out, el)?;
            } else if is_inline {
                // Inline: serialize children inline
                for child in node.children() {
                    if let NodeData::Element(_) = child.data() {
                        // recurse inline
                        pretty_print(out, &child, depth)?;
                    } else {
                        serialize_node_inline(out, &child)?;
                    }
                }
                write_end_tag(out, el)?;
            } else {
                // Block element, no element children - text inline with open tag
                for child in node.children() {
                    serialize_node_inline(out, &child)?;
                }
                if !is_void(name) {
                    out.write_all(b"\n")?;
                    write_indent(out, depth)?;
                    write_end_tag(out, el)?;
                }
            }
        }
        _ => {
            node.serialize(out).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
        }
    }
    Ok(())
}

fn pretty_print_child<W: Write>(out: &mut W, node: &NodeRef, depth: usize) -> io::Result<()> {
    match node.data() {
        NodeData::Element(el) => {
            let name = el.name.local.as_ref();
            let is_inline = is_inline_tag(name);
            if is_inline {
                out.write_all(b"\n")?;
                write_indent(out, depth)?;
                pretty_print(out, node, depth)?;
            } else {
                out.write_all(b"\n")?;
                write_indent(out, depth)?;
                pretty_print(out, node, depth)?;
            }
        }
        NodeData::Text(_) => {
            // Text child of a block element with element siblings - if WS only skip, else?
            // From observation, text nodes among element siblings are placed inline.
            serialize_node_inline(out, node)?;
        }
        _ => {
            serialize_node_inline(out, node)?;
        }
    }
    Ok(())
}

fn write_indent<W: Write>(out: &mut W, depth: usize) -> io::Result<()> {
    for _ in 0..depth {
        out.write_all(b"  ")?;
    }
    Ok(())
}

fn write_start_tag<W: Write>(out: &mut W, el: &ElementData) -> io::Result<()> {
    out.write_all(b"<")?;
    out.write_all(el.name.local.as_ref().as_bytes())?;
    let attrs = el.attributes.borrow();
    // Already alphabetized in kuchiki's attributes map (BTreeMap)
    for (name, attr) in attrs.map.iter() {
        out.write_all(b" ")?;
        out.write_all(name.local.as_ref().as_bytes())?;
        out.write_all(b"=\"")?;
        write_attr_value(out, &attr.value)?;
        out.write_all(b"\"")?;
    }
    out.write_all(b">")?;
    Ok(())
}

fn write_end_tag<W: Write>(out: &mut W, el: &ElementData) -> io::Result<()> {
    let name = el.name.local.as_ref();
    if is_void(name) {
        return Ok(());
    }
    out.write_all(b"</")?;
    out.write_all(name.as_bytes())?;
    out.write_all(b">")?;
    Ok(())
}

fn write_attr_value<W: Write>(out: &mut W, v: &str) -> io::Result<()> {
    for c in v.chars() {
        match c {
            '&' => out.write_all(b"&amp;")?,
            '"' => out.write_all(b"&quot;")?,
            '\u{a0}' => out.write_all(b"&nbsp;")?,
            _ => {
                let mut buf = [0u8; 4];
                let s = c.encode_utf8(&mut buf);
                out.write_all(s.as_bytes())?;
            }
        }
    }
    Ok(())
}

fn is_void(name: &str) -> bool {
    matches!(
        name,
        "area" | "base" | "br" | "col" | "embed" | "hr" | "img"
            | "input" | "link" | "meta" | "param" | "source"
            | "track" | "wbr"
    )
}

fn serialize_node_inline<W: Write>(out: &mut W, node: &NodeRef) -> io::Result<()> {
    node.serialize(out).map_err(|e| io::Error::new(io::ErrorKind::Other, e))
}

use clap::{App, AppSettings, Arg};
use std::fs::File;
use std::io::{self, Read, Write};

use kuchiki::iter::NodeIterator;
use kuchiki::traits::TendrilSink;
use kuchiki::{ElementData, NodeData, NodeRef};

fn main() {
    let matches = App::new("executable")
        .version("0.4.0")
        .author("Michael Maclean <michael@mgdm.net>")
        .about("Runs CSS selectors on HTML")
        .setting(AppSettings::AllowLeadingHyphen)
        .arg(
            Arg::with_name("filename")
                .short("f")
                .long("filename")
                .value_name("FILE")
                .help("The input file. Defaults to stdin")
                .takes_value(true),
        )
        .arg(
            Arg::with_name("output")
                .short("o")
                .long("output")
                .value_name("FILE")
                .help("The output file. Defaults to stdout")
                .takes_value(true),
        )
        .arg(
            Arg::with_name("pretty")
                .short("p")
                .long("pretty")
                .help("Pretty-print the serialised output"),
        )
        .arg(
            Arg::with_name("text")
                .short("t")
                .long("text")
                .help("Output only the contents of text nodes inside selected elements"),
        )
        .arg(
            Arg::with_name("ignore_whitespace")
                .short("w")
                .long("ignore-whitespace")
                .help("When printing text nodes, ignore those that consist entirely of whitespace"),
        )
        .arg(
            Arg::with_name("attribute")
                .short("a")
                .long("attribute")
                .value_name("attribute")
                .help("Only return this attribute (if present) from selected elements")
                .takes_value(true),
        )
        .arg(
            Arg::with_name("base")
                .short("b")
                .long("base")
                .value_name("base")
                .help("Use this URL as the base for links")
                .takes_value(true),
        )
        .arg(
            Arg::with_name("detect_base")
                .short("B")
                .long("detect-base")
                .help("Try to detect the base URL from the <base> tag in the document. If not found, default to the value of --base, if supplied"),
        )
        .arg(
            Arg::with_name("remove_nodes")
                .short("r")
                .long("remove-nodes")
                .value_name("SELECTOR")
                .help("Remove nodes matching this expression before output. May be specified multiple times")
                .takes_value(true)
                .multiple(true)
                .number_of_values(1),
        )
        .arg(
            Arg::with_name("selector")
                .help("The CSS expression to select")
                .default_value("html")
                .multiple(true),
        )
        .get_matches();

    let mut input: Box<dyn Read> = match matches.value_of("filename") {
        Some(filename) => Box::new(
            File::open(filename).expect("should have opened input file"),
        ),
        None => Box::new(io::stdin()),
    };
    let mut output: Box<dyn Write> = match matches.value_of("output") {
        Some(filename) => Box::new(
            File::create(filename).expect("should have created output file"),
        ),
        None => Box::new(io::stdout()),
    };

    let mut input_buf = String::new();
    input
        .read_to_string(&mut input_buf)
        .expect("should have read input");

    let document = kuchiki::parse_html().one(input_buf);

    // Remove nodes if -r supplied
    if let Some(remove_selectors) = matches.values_of("remove_nodes") {
        for sel in remove_selectors {
            let to_remove: Vec<NodeRef> = match document.select(sel) {
                Ok(iter) => iter.map(|d| d.as_node().clone()).collect(),
                Err(_) => panic!("Failed to parse CSS selector: ()"),
            };
            for n in to_remove {
                n.detach();
            }
        }
    }

    // Determine base URL: -B walks document; fallback to -b
    let mut base_url: Option<url::Url> = None;
    if matches.is_present("detect_base") {
        if let Ok(matches_iter) = document.select("base") {
            for base_node in matches_iter {
                let attrs = base_node.attributes.borrow();
                if let Some(href) = attrs.get("href") {
                    if !href.is_empty() {
                        if let Ok(u) = url::Url::parse(href) {
                            base_url = Some(u);
                            break;
                        }
                    }
                }
            }
        }
    }
    if base_url.is_none() {
        if let Some(b) = matches.value_of("base") {
            if let Ok(u) = url::Url::parse(b) {
                base_url = Some(u);
            }
        }
    }

    // Apply base URL to <a href>, <link href>, <area href>
    if let Some(base) = &base_url {
        if let Ok(iter) = document.select("a, link, area") {
            for el in iter {
                let mut attrs = el.attributes.borrow_mut();
                if let Some(href) = attrs.get("href").map(|s| s.to_owned()) {
                    if let Ok(resolved) = base.join(&href) {
                        attrs.insert("href", resolved.to_string());
                    }
                }
            }
        }
    }

    // Build selector
    let sel_parts: Vec<&str> = matches.values_of("selector").unwrap().collect();
    let selector_str = sel_parts.join(" ");

    let select_iter = document.select(&selector_str)
        .unwrap_or_else(|_| panic!("Failed to parse CSS selector: ()"));

    let selected: Vec<NodeRef> = select_iter.map(|d| d.as_node().clone()).collect();

    let attr_opt = matches.value_of("attribute").map(|s| s.to_string());
    let text_mode = matches.is_present("text");
    let ignore_ws = matches.is_present("ignore_whitespace");
    let pretty = matches.is_present("pretty");

    for node in &selected {
        if let Some(attr) = &attr_opt {
            if let Some(elt) = node.as_element() {
                let attrs = elt.attributes.borrow();
                if let Some(val) = attrs.get(attr.as_str()) {
                    output.write_all(val.as_bytes()).expect("write");
                    output.write_all(b"\n").expect("write");
                }
            }
        } else if text_mode {
            if ignore_ws {
                for t in node.descendants().text_nodes() {
                    let s = t.borrow();
                    if !s.trim().is_empty() {
                        output.write_all(s.as_bytes()).expect("write");
                        output.write_all(b"\n").expect("write");
                    }
                }
                output.write_all(b"\n").expect("write");
            } else {
                for t in node.descendants().text_nodes() {
                    let s = t.borrow();
                    output.write_all(s.as_bytes()).expect("write");
                }
                output.write_all(b"\n").expect("write");
            }
        } else if pretty {
            pretty_print(&mut *output, node, 0).expect("write");
            output.write_all(b"\n").expect("write");
        } else {
            node.serialize(&mut *output).expect("serialize");
            output.write_all(b"\n").expect("write");
        }
    }
}

