// Pretty-print an element. `text_break` indicates whether the element's
// immediate first content should be placed on a new indented line.
fn pretty_print<W: Write + ?Sized>(out: &mut W, node: &NodeRef, depth: usize, text_break: bool) -> io::Result<()> {
    match node.data() {
        NodeData::Element(el) => {
            let name = el.name.local.as_ref();
            let is_inline = is_inline_tag(name);
            let has_block_child = node.children().any(|c| match c.data() {
                NodeData::Element(ed) => !is_inline_tag(ed.name.local.as_ref()),
                _ => false,
            });
            let has_any_child = node.children().next().is_some();

            write_start_tag(out, el)?;

            if has_block_child {
                // Has at least one block element child: indent children
                let mut prev_block = text_break;
                for child in node.children() {
                    match child.data() {
                        NodeData::Element(child_el) => {
                            let child_inline = is_inline_tag(child_el.name.local.as_ref());
                            out.write_all(b"\n")?;
                            write_indent(out, depth + 1)?;
                            pretty_print(out, &child, depth + 1, prev_block)?;
                            prev_block = !child_inline;
                        }
                        NodeData::Text(_) => {
                            if prev_block {
                                out.write_all(b"\n")?;
                                write_indent(out, depth + 1)?;
                            }
                            serialize_node_inline(out, &child)?;
                            prev_block = false;
                        }
                        _ => {
                            if prev_block {
                                out.write_all(b"\n")?;
                                write_indent(out, depth + 1)?;
                            }
                            serialize_node_inline(out, &child)?;
                            prev_block = false;
                        }
                    }
                }
                if !is_void(name) {
                    out.write_all(b"\n")?;
                    write_indent(out, depth)?;
                    write_end_tag(out, el)?;
                }
            } else {
                // No block element children — emit children inline.
                // If text_break, emit leading break+indent before first child;
                // the FIRST child element (if any) gets text_break propagated.
                let mut first = true;
                for child in node.children() {
                    if first && text_break {
                        out.write_all(b"\n")?;
                        write_indent(out, depth + 1)?;
                    }
                    match child.data() {
                        NodeData::Element(_) => {
                            pretty_print(out, &child, depth + 1, first && text_break)?;
                        }
                        _ => {
                            serialize_node_inline(out, &child)?;
                        }
                    }
                    first = false;
                }
                if !is_inline {
                    out.write_all(b"\n")?;
                    write_indent(out, depth)?;
                }
                if !is_void(name) {
                    write_end_tag(out, el)?;
                }
                let _ = has_any_child; // suppress unused warning
            }
        }
        _ => {
            serialize_node_inline(out, node)?;
        }
    }
    Ok(())
}

