            for base_node in matches_iter {
                let attrs = base_node.attributes.borrow();
                if let Some(href) = attrs.get("href") {
                    if !href.is_empty() {
                        if let Ok(u) = url::Url::parse(href) {
                            base_url = Some(u);
                            break;
                        }
                    }
                }
            }
        }
    }
    if base_url.is_none() {
        if let Some(b) = matches.value_of("base") {
            if let Ok(u) = url::Url::parse(b) {
                base_url = Some(u);
            }
        }
    }

    // Build selector
    let sel_parts: Vec<&str> = matches.values_of("selector").unwrap().collect();
    let selector_str = sel_parts.join(" ");

    let select_iter = document.select(&selector_str)
        .unwrap_or_else(|_| panic!("Failed to parse CSS selector: ()"));

    let selected: Vec<NodeRef> = select_iter.map(|d| d.as_node().clone()).collect();

    let attr_opt = matches.value_of("attribute").map(|s| s.to_string());
    let text_mode = matches.is_present("text");
    let ignore_ws = matches.is_present("ignore_whitespace");
    let pretty = matches.is_present("pretty");

    for node in &selected {
        // Lazy URL rewriting: if base_url set and this node is <a>/<link>/<area>,
        // rewrite its href before serialization.
        if let Some(base) = &base_url {
            if let Some(el) = node.as_element() {
                let name = el.name.local.as_ref();
                if name == "a" || name == "link" || name == "area" {
                    let mut attrs = el.attributes.borrow_mut();
                    if let Some(href) = attrs.get("href").map(|s| s.to_owned()) {
                        if let Ok(resolved) = base.join(&href) {
                            attrs.insert("href", resolved.to_string());
                        }
                    }
                }
            }
        }
        if let Some(attr) = &attr_opt {
            if let Some(elt) = node.as_element() {
                let attrs = elt.attributes.borrow();
                if let Some(val) = attrs.get(attr.as_str()) {
                    output.write_all(val.as_bytes()).expect("write");
                    output.write_all(b"\n").expect("write");
                }
            }
        } else if text_mode {
            if ignore_ws {
                for t in node.descendants().text_nodes() {
                    let s = t.borrow();
                    if !s.trim().is_empty() {
                        output.write_all(s.as_bytes()).expect("write");
                        output.write_all(b"\n").expect("write");
                    }
                }
                output.write_all(b"\n").expect("write");
            } else {
                for t in node.descendants().text_nodes() {
                    let s = t.borrow();
                    output.write_all(s.as_bytes()).expect("write");
                }
                output.write_all(b"\n").expect("write");
            }
        } else if pretty {
            // Leading newline for block-level root
            if let Some(el) = node.as_element() {
                if !is_inline_tag(el.name.local.as_ref()) {
                    output.write_all(b"\n").expect("write");
                }
            }
            pretty_print(&mut *output, node, 0, false).expect("write");
            output.write_all(b"\n").expect("write");
        } else {
            serialize_node_inline(&mut *output, node).expect("serialize");
            output.write_all(b"\n").expect("write");
        }
    }
}

fn is_inline_tag(name: &str) -> bool {
    matches!(
        name,
        "a" | "abbr" | "acronym" | "b" | "bdi" | "bdo" | "big" | "button"
            | "cite" | "code" | "data" | "dfn" | "em" | "embed"
            | "i" | "iframe" | "img" | "input" | "ins" | "del"
            | "kbd" | "label" | "map" | "mark" | "meter"
            | "object" | "output" | "picture" | "progress"
            | "q" | "ruby" | "s" | "samp" | "script" | "select"
            | "small" | "span" | "strong" | "sub" | "sup"
            | "textarea" | "time" | "tt" | "u" | "var" | "wbr"
    )
}

// Pretty-print an element. `text_break` indicates whether the element's
// immediate first content should be placed on a new indented line.
fn pretty_print<W: Write + ?Sized>(out: &mut W, node: &NodeRef, depth: usize, text_break: bool) -> io::Result<()> {
    match node.data() {
        NodeData::Element(el) => {
            let name = el.name.local.as_ref();
            let is_inline = is_inline_tag(name);
            let has_block_child = node.children().any(|c| match c.data() {
                NodeData::Element(ed) => !is_inline_tag(ed.name.local.as_ref()),
                _ => false,
            });
            let has_any_child = node.children().next().is_some();

            write_start_tag(out, el)?;

            if has_block_child {
                // Has at least one block element child: indent block children
                let mut prev_block = text_break;
                for child in node.children() {
                    match child.data() {
                        NodeData::Element(child_el) => {
                            let child_inline = is_inline_tag(child_el.name.local.as_ref());
                            if !child_inline {
                                // Block: always break+indent before
                                out.write_all(b"\n")?;
                                write_indent(out, depth + 1)?;
                                pretty_print(out, &child, depth + 1, prev_block)?;
                                prev_block = true;
                            } else {
                                // Inline child: break only if prev_block
                                if prev_block {
                                    out.write_all(b"\n")?;
                                    write_indent(out, depth + 1)?;
                                }
                                pretty_print(out, &child, depth + 1, prev_block)?;
                                prev_block = false;
                            }
                        }
                        NodeData::Text(t) => {
                            let s = t.borrow();
                            if s.trim().is_empty() {
                                // skip whitespace-only text nodes in pretty mode
                                continue;
                            }
                            if prev_block {
                                out.write_all(b"\n")?;
                                write_indent(out, depth + 1)?;
                            }
                            out.write_all(s.as_bytes())?;
                            prev_block = false;
                        }
                        _ => {
                            if prev_block {
                                out.write_all(b"\n")?;
                                write_indent(out, depth + 1)?;
                            }
                            serialize_node_inline(out, &child)?;
                            prev_block = false;
                        }
                    }
                }
                if !is_inline {
                    out.write_all(b"\n")?;
                    write_indent(out, depth)?;
                }
                if !is_void(name) {
                    write_end_tag(out, el)?;
                }
            } else {
                // No block element children — emit children inline.
                // If text_break, emit leading break+indent before first child.
                let mut first = true;
                for child in node.children() {
                    if first && text_break {
                        out.write_all(b"\n")?;
                        write_indent(out, depth + 1)?;
                    }
                    match child.data() {
                        NodeData::Element(_) => {
                            pretty_print(out, &child, depth + 1, first && text_break)?;
                        }
                        _ => {
                            serialize_node_inline(out, &child)?;
                        }
                    }
                    first = false;
                }
                if !is_inline {
                    out.write_all(b"\n")?;
                    write_indent(out, depth)?;
                }
                if !is_void(name) {
                    write_end_tag(out, el)?;
                }
                let _ = has_any_child;
            }
        }
        _ => {
            serialize_node_inline(out, node)?;
        }
    }
    Ok(())
}

fn write_indent<W: Write + ?Sized>(out: &mut W, depth: usize) -> io::Result<()> {
    for _ in 0..depth {
        out.write_all(b"  ")?;
    }
    Ok(())
}

fn write_start_tag<W: Write + ?Sized>(out: &mut W, el: &ElementData) -> io::Result<()> {
    out.write_all(b"<")?;
    out.write_all(el.name.local.as_ref().as_bytes())?;
    let attrs = el.attributes.borrow();
    // Already alphabetized in kuchiki's attributes map (BTreeMap)
    for (name, attr) in attrs.map.iter() {
        out.write_all(b" ")?;
        out.write_all(name.local.as_ref().as_bytes())?;
        out.write_all(b"=\"")?;
        write_attr_value(out, &attr.value)?;
        out.write_all(b"\"")?;
    }
    out.write_all(b">")?;
    Ok(())
}

fn write_end_tag<W: Write + ?Sized>(out: &mut W, el: &ElementData) -> io::Result<()> {
    let name = el.name.local.as_ref();
    if is_void(name) {
        return Ok(());
    }
    out.write_all(b"</")?;
    out.write_all(name.as_bytes())?;
    out.write_all(b">")?;
    Ok(())
}

fn write_attr_value<W: Write + ?Sized>(out: &mut W, v: &str) -> io::Result<()> {
    for c in v.chars() {
        match c {
            '&' => out.write_all(b"&amp;")?,
            '"' => out.write_all(b"&quot;")?,
            '\u{a0}' => out.write_all(b"&nbsp;")?,
            _ => {
                let mut buf = [0u8; 4];
                let s = c.encode_utf8(&mut buf);
                out.write_all(s.as_bytes())?;
            }
        }
    }
    Ok(())
}

fn is_void(name: &str) -> bool {
    matches!(
        name,
        "area" | "base" | "br" | "col" | "embed" | "hr" | "img"
            | "input" | "link" | "meta" | "param" | "source"
            | "track" | "wbr"
    )
}

fn serialize_node_inline<W: Write + ?Sized>(out: &mut W, node: &NodeRef) -> io::Result<()> {
    // Need a sized writer for kuchiki's API; wrap with a small adapter
    struct Adapter<'a, W: ?Sized>(&'a mut W);
    impl<'a, W: Write + ?Sized> Write for Adapter<'a, W> {
        fn write(&mut self, buf: &[u8]) -> io::Result<usize> { self.0.write(buf) }
        fn flush(&mut self) -> io::Result<()> { self.0.flush() }
    }
    let mut a = Adapter(out);
    node.serialize(&mut a).map_err(|e| io::Error::new(io::ErrorKind::Other, e))
}

